import java.util.Optional;
public class FlatMapDemo {
    static Optional<String> findUser(int id) {
        return id > 0 ? Optional.of("User" + id) : Optional.empty();
    }
    static Optional<String> findEmail(String name) {
        return name.startsWith("User") ? Optional.of(name + "@example.com") : Optional.empty();
    }
    public static void main(String[] args) {
        Optional<String> email = Optional.of(1)
            .flatMap(id -> findUser(id))
            .flatMap(name -> findEmail(name));
        System.out.println(email.orElse("none"));
        Optional<String> missing = Optional.of(-1)
            .flatMap(id -> findUser(id))
            .flatMap(name -> findEmail(name));
        System.out.println(missing.orElse("none"));
    }
}
